#!/usr/bin/env node
// Preview a pack generated by the API (audio in Supabase, no local files).
// Usage: node scripts/preview-from-api-pack.js [packJsonPath] [ideaIndex] [clipIndex]
// Defaults: /tmp/snapmind_pack.json, idea 0, clip 0

require("dotenv").config();

const fs = require("fs");
const path = require("path");
const https = require("https");
const http = require("http");

const {
  buildShortSceneImagePrompt,
  generateShortSceneImage,
  resolveGeminiImageConfig,
} = require("../shared/backend-core/dist/cjs/geminiImage");

const {
  createSupabaseAudioStorageClient,
  resolveSupabaseAudioStorageConfig,
} = require("../shared/backend-core/dist/cjs/supabaseStorage");

function ensureDir(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true });
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function escapeHtml(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function downloadUrl(url) {
  return new Promise((resolve, reject) => {
    const lib = url.startsWith("https") ? https : http;
    lib.get(url, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        return downloadUrl(res.headers.location).then(resolve).catch(reject);
      }
      if (res.statusCode !== 200) {
        return reject(new Error(`Download failed with status ${res.statusCode}`));
      }
      const chunks = [];
      res.on("data", (chunk) => chunks.push(chunk));
      res.on("end", () => resolve(Buffer.concat(chunks)));
      res.on("error", reject);
    }).on("error", reject);
  });
}

function buildPreviewHtml({ pack, idea, clip, audioFileName, scenes }) {
  const slidesJson = JSON.stringify(
    scenes.map((scene, index) => ({
      id: scene.id || `scene-${index + 1}`,
      order: Number(scene.order || index + 1) || index + 1,
      headline: scene.headline || "",
      body: scene.body || "",
      callouts: Array.isArray(scene.callouts) ? scene.callouts : [],
      narration: scene.narration || "",
      estimatedSec: Number(scene.estimatedSec || 12) || 12,
      imageFile: scene.localImageFile || "",
      startMs: Number(scene.segment?.startMs || 0) || 0,
      endMs: Number(scene.segment?.endMs || 0) || 0,
    })),
    null,
    2
  );

  const packTitle = escapeHtml(pack?.title || "Short preview");
  const ideaTitle = escapeHtml(idea?.title || "Idea");
  const clipTitle = escapeHtml(clip?.title || ideaTitle);
  const audioSrc = escapeHtml(audioFileName || "");
  const teaser = escapeHtml(clip?.teaser || idea?.teaser || "");

  return `<!doctype html>
<html lang="ko">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${packTitle} — ${clipTitle}</title>
    <style>
      :root {
        color-scheme: light;
        --bg: #f5f6f2;
        --paper: #fffdf7;
        --ink: #10273a;
        --muted: #66798a;
        --accent: #e0aa00;
        --accent-2: #5cc0de;
      }
      * { box-sizing: border-box; }
      body {
        margin: 0;
        min-height: 100vh;
        background:
          radial-gradient(circle at top left, rgba(92,192,222,0.12), transparent 35%),
          radial-gradient(circle at top right, rgba(224,170,0,0.10), transparent 30%),
          linear-gradient(180deg, #fbfcf9 0%, var(--bg) 100%);
        color: var(--ink);
        font-family: ui-sans-serif, -apple-system, BlinkMacSystemFont, "Apple SD Gothic Neo", "Noto Sans KR", sans-serif;
        display: flex;
        justify-content: center;
        padding: 24px;
      }
      .app {
        width: min(100%, 1280px);
        display: grid;
        gap: 24px;
        grid-template-columns: minmax(320px, 430px) minmax(280px, 1fr);
        align-items: start;
      }
      .phone {
        background: var(--paper);
        border: 1px solid rgba(16,39,58,0.08);
        border-radius: 36px;
        box-shadow: 0 20px 60px rgba(16,39,58,0.12);
        overflow: hidden;
        position: sticky;
        top: 24px;
      }
      .phone-top {
        padding: 18px 20px 10px;
        border-bottom: 1px solid rgba(16,39,58,0.06);
        background: rgba(255,255,255,0.88);
      }
      .pack-label { font-size: 12px; letter-spacing: 0.08em; text-transform: uppercase; color: var(--muted); margin-bottom: 6px; font-weight: 700; }
      .pack-title { font-size: 24px; line-height: 1.15; margin: 0; font-weight: 900; }
      .scene-stage { padding: 18px; }
      .scene-image {
        width: 100%; aspect-ratio: 9/12; object-fit: cover; border-radius: 26px; display: block;
        background: linear-gradient(135deg, rgba(92,192,222,0.18), rgba(224,170,0,0.10));
        border: 1px solid rgba(16,39,58,0.08);
      }
      .scene-card { margin-top: 16px; padding: 18px; border-radius: 24px; background: linear-gradient(180deg, rgba(255,255,255,0.96), rgba(249,247,240,0.96)); border: 1px solid rgba(16,39,58,0.08); }
      .scene-meta { font-size: 12px; font-weight: 800; letter-spacing: 0.08em; text-transform: uppercase; color: var(--muted); margin-bottom: 8px; }
      .scene-headline { font-size: 28px; line-height: 1.15; margin: 0; font-weight: 900; }
      .scene-body { margin: 14px 0 0; font-size: 17px; line-height: 1.7; }
      .callouts { margin-top: 16px; display: flex; flex-wrap: wrap; gap: 8px; }
      .callout { border-radius: 999px; padding: 8px 12px; font-size: 13px; font-weight: 800; background: rgba(224,170,0,0.12); color: #9a6d00; border: 1px solid rgba(224,170,0,0.28); }
      .controls { margin-top: 18px; padding: 18px; border-top: 1px solid rgba(16,39,58,0.06); }
      .progress-row { display: flex; justify-content: space-between; font-size: 13px; color: var(--muted); margin-bottom: 10px; font-weight: 700; }
      .progress-track { width: 100%; height: 8px; border-radius: 999px; background: rgba(16,39,58,0.08); overflow: hidden; }
      .progress-fill { width: 0%; height: 100%; border-radius: inherit; background: linear-gradient(90deg, var(--accent-2), var(--accent)); }
      audio { width: 100%; margin-top: 16px; }
      .buttons { display: flex; gap: 10px; margin-top: 14px; }
      button { flex: 1; border: 0; border-radius: 16px; padding: 14px 16px; font: inherit; font-weight: 800; cursor: pointer; color: #fffdf7; background: linear-gradient(135deg, #294d66, #173146); }
      button.secondary { background: rgba(16,39,58,0.08); color: var(--ink); }
      .panel { background: rgba(255,255,255,0.66); border: 1px solid rgba(16,39,58,0.08); border-radius: 28px; padding: 24px; box-shadow: 0 20px 60px rgba(16,39,58,0.08); }
      .panel h2 { margin: 0 0 12px; font-size: 26px; }
      .panel p { margin: 0; color: var(--muted); line-height: 1.7; }
      .timeline { margin-top: 20px; display: grid; gap: 12px; }
      .timeline-item { border: 1px solid rgba(16,39,58,0.08); border-radius: 20px; padding: 16px; background: rgba(255,253,247,0.86); cursor: pointer; }
      .timeline-item.active { border-color: rgba(92,192,222,0.45); box-shadow: 0 0 0 3px rgba(92,192,222,0.12); }
      .timeline-item h3 { margin: 0 0 8px; font-size: 18px; }
      .timeline-item small { color: var(--muted); font-weight: 700; }
      .timeline-item p { margin-top: 8px; font-size: 14px; }
      @media (max-width: 980px) { body { padding: 16px; } .app { grid-template-columns: 1fr; } .phone { position: static; } }
    </style>
  </head>
  <body>
    <div class="app">
      <section class="phone">
        <header class="phone-top">
          <div class="pack-label">${packTitle}</div>
          <h1 class="pack-title">${clipTitle}</h1>
        </header>
        <div class="scene-stage">
          <img id="scene-image" class="scene-image" alt="" />
          <article class="scene-card">
            <div id="scene-meta" class="scene-meta">Scene 1</div>
            <h2 id="scene-headline" class="scene-headline">${clipTitle}</h2>
            <p id="scene-body" class="scene-body">${teaser}</p>
            <div id="scene-callouts" class="callouts"></div>
          </article>
        </div>
        <footer class="controls">
          <div class="progress-row">
            <span id="progress-label">Scene 1</span>
            <span id="time-label">0:00 / 0:00</span>
          </div>
          <div class="progress-track"><div id="progress-fill" class="progress-fill"></div></div>
          <audio id="audio" src="${audioSrc}" controls preload="metadata"></audio>
          <div class="buttons">
            <button id="prev" class="secondary" type="button">◀ Prev</button>
            <button id="play" type="button">▶ Play / Pause</button>
            <button id="next" class="secondary" type="button">Next ▶</button>
          </div>
        </footer>
      </section>
      <aside class="panel">
        <h2>${escapeHtml(pack?.title || "")}</h2>
        <p>${escapeHtml(idea?.title || "")}</p>
        <div id="timeline" class="timeline"></div>
      </aside>
    </div>
    <script>
      const slides = ${slidesJson};
      const audio = document.getElementById("audio");
      const imageEl = document.getElementById("scene-image");
      const metaEl = document.getElementById("scene-meta");
      const headlineEl = document.getElementById("scene-headline");
      const bodyEl = document.getElementById("scene-body");
      const calloutsEl = document.getElementById("scene-callouts");
      const progressLabelEl = document.getElementById("progress-label");
      const timeLabelEl = document.getElementById("time-label");
      const progressFillEl = document.getElementById("progress-fill");
      const timelineEl = document.getElementById("timeline");
      let activeIndex = 0;

      function formatTime(seconds) {
        const total = Math.max(0, Math.floor(seconds || 0));
        return Math.floor(total / 60) + ":" + String(total % 60).padStart(2, "0");
      }

      function renderTimeline() {
        timelineEl.innerHTML = "";
        slides.forEach((slide, index) => {
          const item = document.createElement("div");
          item.className = "timeline-item" + (index === activeIndex ? " active" : "");
          item.innerHTML = \`<small>Scene \${index + 1} · \${formatTime(slide.startMs/1000)}–\${formatTime(slide.endMs/1000)}</small><h3>\${slide.headline}</h3><p>\${slide.body}</p>\`;
          item.addEventListener("click", () => seekToSlide(index));
          timelineEl.appendChild(item);
        });
      }

      function renderSlide(index) {
        activeIndex = Math.max(0, Math.min(slides.length - 1, index));
        const slide = slides[activeIndex];
        imageEl.src = slide.imageFile || "";
        metaEl.textContent = "Scene " + (activeIndex + 1) + " / " + slides.length;
        headlineEl.textContent = slide.headline || "";
        bodyEl.textContent = slide.body || "";
        calloutsEl.innerHTML = "";
        (slide.callouts || []).forEach((callout) => {
          const chip = document.createElement("span");
          chip.className = "callout";
          chip.textContent = callout;
          calloutsEl.appendChild(chip);
        });
        progressLabelEl.textContent = "Scene " + (activeIndex + 1) + " / " + slides.length;
        renderTimeline();
      }

      function seekToSlide(index) {
        const slide = slides[index];
        if (slide && Number.isFinite(slide.startMs)) audio.currentTime = slide.startMs / 1000;
        renderSlide(index);
      }

      function syncSlideToAudio() {
        const currentMs = (audio.currentTime || 0) * 1000;
        const index = slides.findIndex((slide, i) => {
          const next = slides[i + 1];
          const ownEndMs = Math.max(slide.startMs || 0, slide.endMs || 0);
          const nextStartMs = next ? Math.max(ownEndMs, next.startMs || 0) : 0;
          const endMs = nextStartMs || ownEndMs || Number.MAX_SAFE_INTEGER;
          return currentMs >= slide.startMs && currentMs < endMs;
        });
        if (index >= 0 && index !== activeIndex) renderSlide(index);
        const duration = audio.duration || 0;
        timeLabelEl.textContent = formatTime(audio.currentTime) + " / " + formatTime(duration);
        progressFillEl.style.width = duration > 0 ? ((audio.currentTime / duration) * 100).toFixed(2) + "%" : "0%";
      }

      document.getElementById("play").addEventListener("click", () => audio.paused ? audio.play().catch(() => {}) : audio.pause());
      document.getElementById("prev").addEventListener("click", () => seekToSlide(Math.max(0, activeIndex - 1)));
      document.getElementById("next").addEventListener("click", () => seekToSlide(Math.min(slides.length - 1, activeIndex + 1)));
      audio.addEventListener("timeupdate", syncSlideToAudio);
      audio.addEventListener("loadedmetadata", syncSlideToAudio);
      renderSlide(0);
    </script>
  </body>
</html>`;
}

async function main() {
  const packJsonPath = process.argv[2] || "/tmp/snapmind_pack.json";
  const ideaIndex = Math.max(0, Number(process.argv[3] || 0) || 0);
  const clipIndex = Math.max(0, Number(process.argv[4] || 0) || 0);

  if (!fs.existsSync(packJsonPath)) {
    throw new Error(`Pack file not found: ${packJsonPath}`);
  }

  const pack = JSON.parse(fs.readFileSync(packJsonPath, "utf8"));
  const idea = Array.isArray(pack?.ideas) ? pack.ideas[ideaIndex] : null;
  if (!idea) throw new Error(`Idea index ${ideaIndex} not found`);

  const clips = Array.isArray(idea.clips) ? idea.clips : [];
  const clip = clips[clipIndex];
  if (!clip) throw new Error(`Clip index ${clipIndex} not found in idea ${ideaIndex}`);

  const tts = clip.tts || {};
  if (tts.audioStatus !== "ready" || !tts.audioPath) {
    throw new Error(`Clip audio is not ready: audioStatus=${tts.audioStatus}`);
  }

  const outDir = path.join("/tmp", `snapmind_preview_${pack.id}`);
  ensureDir(outDir);

  // Download audio from Supabase Storage
  console.log(`Downloading audio: ${tts.audioPath}`);
  const storageConfig = resolveSupabaseAudioStorageConfig({
    supabaseUrl: process.env.SUPABASE_URL,
    serviceRoleKey: process.env.SUPABASE_SERVICE_ROLE_KEY,
    bucketName: tts.bucketName || process.env.SUPABASE_AUDIO_BUCKET || "shorts-audio",
  });

  if (!storageConfig) throw new Error("SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not set");

  const storage = createSupabaseAudioStorageClient(storageConfig);
  const { signedUrl } = await storage.createSignedUrl(tts.audioPath, 3600);
  console.log("Got signed URL, downloading...");
  const audioBytes = await downloadUrl(signedUrl);
  const audioExt = tts.audioPath.endsWith(".wav") ? "wav" : "mp3";
  const audioFileName = `clip-audio.${audioExt}`;
  const audioFilePath = path.join(outDir, audioFileName);
  fs.writeFileSync(audioFilePath, audioBytes);
  console.log(`Audio saved: ${audioFilePath} (${(audioBytes.length / 1024).toFixed(1)} KB)`);

  // Generate scene images
  const imageConfig = resolveGeminiImageConfig({
    apiKey: process.env.GEMINI_API_KEY,
    model: process.env.GEMINI_IMAGE_MODEL,
  });

  if (!imageConfig) throw new Error("GEMINI_API_KEY not set");

  const rawScenes = Array.isArray(clip.scenes) ? clip.scenes : [];
  const segments = Array.isArray(tts.segments) ? tts.segments : [];
  const previewScenes = [];

  for (let i = 0; i < rawScenes.length; i += 1) {
    const scene = rawScenes[i];
    const segment = segments.find((s) => s.sceneId === scene.id) || segments[i] || { startMs: i * 12000, endMs: (i + 1) * 12000 };

    console.log(`Generating image for scene ${i + 1}/${rawScenes.length}: ${scene.headline}`);

    const prompt = buildShortSceneImagePrompt({
      packTitle: pack?.title || "Learning pack",
      ideaTitle: clip?.title || idea?.title || `Idea ${ideaIndex + 1}`,
      languageCode: pack?.languageCode || "ko",
      scene: {
        headline: scene?.headline,
        body: scene?.body,
        callouts: scene?.callouts,
        visualStyle: scene?.visualStyle,
        layoutHint: scene?.layoutHint,
      },
    });

    let image = null;
    for (let attempt = 1; attempt <= 3; attempt++) {
      try {
        image = await generateShortSceneImage({ config: imageConfig, prompt });
        break;
      } catch (err) {
        console.warn(`  Attempt ${attempt} failed: ${err?.message}`);
        if (attempt < 3) await sleep(2000);
        else throw err;
      }
    }

    const imageFileName = `scene-${String(i + 1).padStart(2, "0")}.${image.fileExtension || "png"}`;
    fs.writeFileSync(path.join(outDir, imageFileName), Buffer.from(image.imageBytes));
    console.log(`  Saved: ${imageFileName}`);

    previewScenes.push({ ...scene, localImageFile: imageFileName, segment });
  }

  const htmlPath = path.join(outDir, "preview.html");
  fs.writeFileSync(
    htmlPath,
    buildPreviewHtml({ pack, idea, clip, audioFileName, scenes: previewScenes }),
    "utf8"
  );

  console.log(`\nPreview ready: ${htmlPath}`);
  console.log(`Open with: open "${htmlPath}"`);
}

main().catch((err) => {
  console.error(err?.stack || err);
  process.exit(1);
});
